    subgraph &quot;会话生命周期&quot;
        A[SessionStart] --&gt; B[UserPromptSubmit]
        B --&gt; C[PreToolUse]
        C --&gt; D[PostToolUse]
        D --&gt; E[SessionEnd]
    end

    subgraph &quot;通知事件&quot;
        F[Notification]
        G[Stop]
    end

    subgraph &quot;外部集成&quot;
